const d = $input.first().json;
const dt = new Date();
// Moscow time
const msk = new Date(dt.getTime() + 3*3600000);
const days = ['воскресенье','понедельник','вторник','среда','четверг','пятница','суббота'];
const months = ['января','февраля','марта','апреля','мая','июня','июля','августа','сентября','октября','ноября','декабря'];
const yesterday = new Date(msk.getTime() - 86400000);
const dateStr = `${yesterday.getDate()} ${months[yesterday.getMonth()]} ${yesterday.getFullYear()}`;

let msg = `📊 Отчёт за ${dateStr}\n`;
msg += `━━━━━━━━━━━━━━━━━━━━\n`;

// SITE
const siteOrders = d.site_orders || 0;
const siteGmv = d.site_gmv || 0;
msg += `▎Сайт — ${siteOrders} заказов, ${siteGmv} EUR\n`;

// TOP-30
const top = d.top30 || [];
if (top.length > 0) {
  msg += `Топ по выручке:\n`;
  top.slice(0,10).forEach(p => {
    msg += `• ${p.name} — ${p.rev} EUR (${p.qty} шт)\n`;
  });
  if (top.length > 10) msg += `  ...ещё ${top.length - 10} позиций\n`;
}

// Payment methods
const card = d.gmv_card || 0;
const bal = d.gmv_balance || 0;
if (card > 0 || bal > 0) {
  msg += `\nОплата: картой ${card} EUR (${d.cnt_card || 0} шт), баланс ${bal} EUR (${d.cnt_balance || 0} шт)\n`;
}

// Peaks
const peaks = d.peaks || [];
if (peaks.length > 0) {
  const pkStr = peaks.slice(0,3).map(p => `${p.h}:00 (${p.cnt} зак.)`).join(', ');
  msg += `Пики: ${pkStr}\n`;
}

if (d.cancelled > 0) msg += `Отменено: ${d.cancelled}\n`;

msg += `━━━━━━━━━━━━━━━━━━━━\n`;

// YM
const ymCount = d.ym_count || 0;
const ymRub = d.ym_total_rub || 0;
const ymAvg = ymCount > 0 ? Math.round(ymRub / ymCount) : 0;
const ymOrders = d.ym_orders || [];

if (ymCount > 0) {
  msg += `▎Яндекс Маркет — ${ymCount} заказов, ${ymRub} ₽\n`;
  if (ymOrders.length > 0) {
    msg += `Крупные:\n`;
    ymOrders.forEach(o => {
      msg += `• ${o.rub} ₽ — ${o.city || '—'}\n`;
    });
  }
  const ymGeo = d.ym_geo || [];
  if (ymGeo.length > 0) {
    const moscow = ymGeo.find(g => g.region && g.region.includes('Москв'));
    const total_regions = ymGeo.length;
    if (moscow) {
      msg += `География: Москва (${moscow.orders} зак., ${moscow.total_rub} ₽), регионы (${ymCount - moscow.orders})\n`;
    } else {
      const geoStr = ymGeo.slice(0,3).map(g => `${g.region} (${g.orders})`).join(', ');
      msg += `Geography: ${geoStr}\n`;
    }
  }
  msg += `Средний чек: ${ymAvg} ₽\n`;
  msg += `━━━━━━━━━━━━━━━━━━━━\n`;
}

// Total
msg += `▎Итого: сайт ${siteGmv} EUR`;
if (ymRub > 0) msg += ` + ЯМ ${ymRub} ₽`;
msg += `\n`;

if (top.length >= 2) {
  msg += `Лидеры: ${top[0].name} (${top[0].qty} шт), ${top[1].name} (${top[1].qty} шт)`;
}

return [{ json: { text: msg } }];
